import math

def compute_f(n):
    memo = {}

    def solve(v):
        if v in memo:
            return memo[v]

        res = 1
        limit = int(math.isqrt(v))
        for k in range(limit + 1):
            if k != v:
                res += solve(k)
        memo[v] = res
        return res

    results = {}
    for i in range(n + 1):
        results[i] = solve(i)
    return results

f_values = compute_f(200)

# Print all values
for i in range(0, 101):
    print(f"{i:3d}: {f_values[i]}")
